var e=[{id:`L3_1`,type:`dialog`,speaker:`MERCENARY_VOICE_NULL_A`,text:{KOREA:`IED다! 와이어를 건드리지 마!`,JPN:`IEDだ！　ワイヤに触れるな！`,ENG:`It's an IED! Don't trip the wire!`,TWN:`是IED！別碰到線！`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`MERCENARY_VOICE_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`MERCENARY_VOICE_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L4_1`,type:`dialog`,speaker:`MERCENARY_VOICE_NULL_B`,text:{KOREA:`젠장! 싸구려 야투경에 뭐가 보여야지!!`,JPN:`ちくしょう！　安もんの暗視スコープで何も見えねえ！！`,ENG:`Dammit! I can't see anything with these cheap night goggles!!`,TWN:`該死！就算是便宜的夜視鏡也該看到點東西吧！`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`MERCENARY_VOICE_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`MERCENARY_VOICE_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`MERCENARY_VOICE_NULL_A`,text:{KOREA:`이런 빌어먹을 테러리스트들이!!`,JPN:`このくそテロリストが！！`,ENG:`Those good-for-nothing terrorists!!`,TWN:`那些該死的恐怖份子！！`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`MERCENARY_VOICE_NULL_A`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`잡아만 둔다는 걸 그만 무리해 버렸군. 나도 참 워커 홀릭이야.`,JPN:`抑えるだけにしておくつもりだったが、つい無理してしまった。俺も相当な仕事中毒だな。`,ENG:`Guess I overdid it again. Geez, I'm such a workaholic.`,TWN:`光是這樣就已經很勉強呢，我真是個工作狂。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`그쪽은 어떻지, 이유리?`,JPN:`そちらはどうだ、カスカベ。`,ENG:`How's it on your end, Yuri?`,TWN:`李悠麗，你那邊情況如何？`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`용병들은 모두 해치웠어. 지금 타깃을 찾는 중이야.`,JPN:`傭兵は全部片付けた。今ターゲットを探してる。`,ENG:`The goons are down. Looking for our target now.`,TWN:`傭兵都已經處理完畢，現在正在尋找目標。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`호흡이 거칠군. 설마 부상이라도 입은 거냐?`,JPN:`呼吸が乱れているな。まさか怪我でもしたのか？`,ENG:`You're breathing heavily. Are you wounded?`,TWN:`你的呼吸有點急促，是受傷了嗎？`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`많이 다치진 않았어. 몇 발 스친 정도야.`,JPN:`たいした怪我じゃない。何発かかすっただけだよ。`,ENG:`Not much. Just a few scratches here and there.`,TWN:`沒什麼大礙，一點擦傷而已。`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`대장은 알잖아. 한숨 푹 자면…….`,JPN:`隊長は知ってるだろ。一晩ぐっすり寝れば……`,ENG:`You know how it is, Captain. I just need a good night's sleep and─`,TWN:`隊長你也知道，只要大睡一場……`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`이유리? 왜 갑자기 말이 없나? 무슨 문제라도 생긴 건가?`,JPN:`カスカベ？　いきなり黙ってどうした？　何か問題でもあるのか？`,ENG:`Lee Yuri? What's going on? Why'd you stop talking?`,TWN:`李悠麗？怎麼突然沒聲音？發生什麼事？`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`SNAKE_EP9HALF_NULL_NULL`,text:{KOREA:`컥……. 크륵……. 커억…….`,JPN:`ぐっ……がはっ……くうっ……`,ENG:`Kuh...! Khhkkk...! Krrgh...!`,TWN:`咳……咳咳……咳咳……`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`LEVIA_MILITIA_NULL_NULL`,text:{KOREA:`어서 와요, 유리 언니.`,JPN:`あ、ユリさん。`,ENG:`Hello, Yuri.`,TWN:`嗨～悠麗姊姊。`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:{char_id:`LEVIA_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`LEVIA_MILITIA_NULL_NULL`,text:{KOREA:`그래도 너무 늦었다. 저 아니었으면 타깃이 도망칠 뻔했잖아요.`,JPN:`なかなか来ないんだもん。私がいなかったらターゲットに逃げられるところだったんですよ？  `,ENG:`What took you so long? He would've got away if it weren't for me.`,TWN:`動作太慢啦，還好有我在，差點被目標給逃走。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`LEVIA_MILITIA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`잠깐, 그 목소리는…….`,JPN:`おい、その声は……`,ENG:`Wait… That voice…`,TWN:`等等，這個聲音是……`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`맞아. 레비아야.`,JPN:`そう。レヴィアだ。`,ENG:`Yeah. It's Levia.`,TWN:`沒錯，是莉維亞。`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};